"use strict";
export const calculateCardIndex = (x, l) => {
  return (x < 0 ? x + l : x) % l;
};
export const calculateFirstCardIndex = (i, firstVis, firstVisIdx, idx) => {
  return idx(i - firstVis + firstVisIdx);
};
export const calculateRank = (firstVis, firstVisIdx, position, l, y) => {
  return firstVis - (y < 0 ? l : 0) + position - firstVisIdx + (y < 0 && firstVis === 0 ? l : 0);
};
